import React, { useState, useEffect } from 'react';
import API from '../api/axios';

const ComplaintsList = () => {
    const [complaints, setComplaints] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedComplaint, setSelectedComplaint] = useState(null);
    const [userRole, setUserRole] = useState('');
    const [users, setUsers] = useState([]);
    const [filters, setFilters] = useState({ status: '', type: '' });

    const statusOptions = ['Pending', 'Assigned', 'In-Progress', 'On-Hold', 'Completed'];
    const typeOptions = ['PC Hardware', 'PC Software', 'Application Issues', 'Network', 'Electronics', 'Plumbing'];

    useEffect(() => {
        const role = localStorage.getItem('role');
        setUserRole(role);
        fetchComplaints();
        if (role === 'SuperAdmin') {
            fetchUsers();
        }
    }, []);

    const fetchComplaints = async () => {
        try {
            const { data } = await API.get('/complaints');
            setComplaints(data);
        } catch (err) {
            alert('Error fetching complaints');
        } finally {
            setLoading(false);
        }
    };

    const fetchUsers = async () => {
        try {
            const { data } = await API.get('/master/users');
            setUsers(data.filter(u => ['Plumber', 'Electrician', 'Networking Staff', 'Software Developer'].includes(u.role)));
        } catch (err) {
            console.error('Error fetching users:', err);
        }
    };

    const handleAssign = async (complaintId, assigneeId) => {
        try {
            await API.put(`/complaints/${complaintId}/assign`, { assignedTo: assigneeId });
            fetchComplaints();
            setSelectedComplaint(null);
            alert('Complaint assigned successfully!');
        } catch (err) {
            alert('Error assigning complaint');
        }
    };

    const handleStatusChange = async (complaintId, newStatus) => {
        try {
            await API.put(`/complaints/${complaintId}/status`, { status: newStatus });
            fetchComplaints();
            setSelectedComplaint(null);
            alert('Status updated successfully!');
        } catch (err) {
            alert('Error updating status');
        }
    };

    const isSuperAdmin = userRole === 'SuperAdmin';
    const isStaff = ['Plumber', 'Electrician', 'Networking Staff', 'Software Developer'].includes(userRole);

    const filteredComplaints = complaints.filter(c => {
        if (filters.status && c.status !== filters.status) return false;
        if (filters.type && c.complaintType !== filters.type) return false;
        return true;
    });

    if (loading) return <div style={{ padding: '40px', color: 'white' }}>Loading...</div>;

    return (
        <div style={{ padding: '40px', color: 'white', background: '#0f172a', minHeight: '100vh' }}>
            <h2 style={{ fontSize: '2rem', marginBottom: '30px' }}>Complaints List</h2>

            {/* Filters */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px', marginBottom: '30px' }}>
                <div>
                    <label style={{ display: 'block', marginBottom: '5px' }}>Filter by Status</label>
                    <select 
                        value={filters.status}
                        onChange={e => setFilters({...filters, status: e.target.value})}
                        style={inputStyle}
                    >
                        <option value="">All Status</option>
                        {statusOptions.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                </div>
                <div>
                    <label style={{ display: 'block', marginBottom: '5px' }}>Filter by Type</label>
                    <select 
                        value={filters.type}
                        onChange={e => setFilters({...filters, type: e.target.value})}
                        style={inputStyle}
                    >
                        <option value="">All Types</option>
                        {typeOptions.map(t => <option key={t} value={t}>{t}</option>)}
                    </select>
                </div>
            </div>

            {/* Complaints Table */}
            <div style={{ overflowX: 'auto' }}>
                <table style={tableStyle}>
                    <thead>
                        <tr style={{ background: '#1e293b' }}>
                            <th>ID</th>
                            <th>Block</th>
                            <th>Room</th>
                            <th>Type</th>
                            <th>Status</th>
                            <th>Raised By</th>
                            <th>Assigned To</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredComplaints.length === 0 ? (
                            <tr><td colSpan="8" style={{ textAlign: 'center', padding: '20px' }}>No complaints found</td></tr>
                        ) : (
                            filteredComplaints.map(complaint => (
                                <tr key={complaint._id} style={{ borderBottom: '1px solid #334155' }}>
                                    <td style={{ fontSize: '0.85rem' }}>{complaint._id.substring(0, 8)}</td>
                                    <td>{complaint.blockName}</td>
                                    <td>{complaint.roomNumber}</td>
                                    <td>{complaint.complaintType}</td>
                                    <td>
                                        <span style={{
                                            padding: '5px 10px',
                                            borderRadius: '5px',
                                            background: getStatusColor(complaint.status),
                                            fontSize: '0.85rem'
                                        }}>
                                            {complaint.status}
                                        </span>
                                    </td>
                                    <td>{complaint.user?.userName}</td>
                                    <td>{complaint.assignedTo?.userName || 'Unassigned'}</td>
                                    <td>
                                        <button 
                                            onClick={() => setSelectedComplaint(complaint)}
                                            style={{ padding: '5px 10px', background: '#3b82f6', border: 'none', borderRadius: '5px', color: 'white', cursor: 'pointer', fontSize: '0.85rem' }}
                                        >
                                            View
                                        </button>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {/* Detail Modal */}
            {selectedComplaint && (
                <div style={modalOverlayStyle}>
                    <div style={modalStyle}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
                            <h3>Complaint Details</h3>
                            <button onClick={() => setSelectedComplaint(null)} style={{ background: 'none', border: 'none', color: 'white', fontSize: '1.5rem', cursor: 'pointer' }}>×</button>
                        </div>

                        <div style={{ marginBottom: '15px' }}>
                            <label>Block:</label>
                            <p>{selectedComplaint.blockName}</p>
                        </div>
                        <div style={{ marginBottom: '15px' }}>
                            <label>Room:</label>
                            <p>{selectedComplaint.roomNumber}</p>
                        </div>
                        <div style={{ marginBottom: '15px' }}>
                            <label>Type:</label>
                            <p>{selectedComplaint.complaintType}</p>
                        </div>
                        <div style={{ marginBottom: '15px' }}>
                            <label>Remarks:</label>
                            <p>{selectedComplaint.complaintRemarks}</p>
                        </div>
                        <div style={{ marginBottom: '15px' }}>
                            <label>Raised By:</label>
                            <p>{selectedComplaint.user?.userName} ({selectedComplaint.user?.email})</p>
                        </div>

                        {/* Super Admin - Assign */}
                        {isSuperAdmin && (
                            <div style={{ marginBottom: '15px' }}>
                                <label>Assign To:</label>
                                <select 
                                    onChange={e => handleAssign(selectedComplaint._id, e.target.value)}
                                    style={inputStyle}
                                >
                                    <option value="">Select Staff</option>
                                    {users.map(u => <option key={u._id} value={u._id}>{u.userName} ({u.role})</option>)}
                                </select>
                            </div>
                        )}

                        {/* Status Change */}
                        {(isSuperAdmin || (isStaff && selectedComplaint.assignedTo?.email === localStorage.getItem('email'))) && (
                            <div style={{ marginBottom: '15px' }}>
                                <label>Update Status:</label>
                                <select 
                                    value={selectedComplaint.status}
                                    onChange={e => handleStatusChange(selectedComplaint._id, e.target.value)}
                                    style={inputStyle}
                                >
                                    {statusOptions.map(s => <option key={s} value={s}>{s}</option>)}
                                </select>
                            </div>
                        )}

                        <button 
                            onClick={() => setSelectedComplaint(null)}
                            style={{ padding: '10px 20px', background: '#6b7280', border: 'none', borderRadius: '5px', color: 'white', cursor: 'pointer', width: '100%' }}
                        >
                            Close
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

const getStatusColor = (status) => {
    const colors = {
        'Pending': '#f59e0b',
        'Assigned': '#8b5cf6',
        'In-Progress': '#3b82f6',
        'On-Hold': '#ef4444',
        'Completed': '#10b981'
    };
    return colors[status] || '#6b7280';
};

const inputStyle = { 
    width: '100%', 
    padding: '10px', 
    marginTop: '5px',
    borderRadius: '5px', 
    border: '1px solid #334155', 
    background: '#1e293b', 
    color: 'white',
    boxSizing: 'border-box'
};

const tableStyle = {
    width: '100%',
    borderCollapse: 'collapse',
    marginTop: '20px',
    border: '1px solid #334155',
    fontSize: '0.9rem'
};

const modalOverlayStyle = {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    background: 'rgba(0,0,0,0.7)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    zIndex: 1000
};

const modalStyle = {
    background: '#1e293b',
    padding: '30px',
    borderRadius: '10px',
    maxWidth: '500px',
    width: '90%',
    color: 'white',
    border: '1px solid #334155'
};

export default ComplaintsList;
